mapper.select:
SELECT s.id AS signupId, s.event_id AS eventId, e.title AS eventTitle, e.cover_url AS coverUrl, e.location, e.start_time AS startTime, e.end_time AS endTime, e.signup_deadline AS signupDeadline, e.need_audit AS needAudit, s.status, s.signup_time AS signupTime, s.audit_time AS auditTime, s.cancel_time AS cancelTime, IFNULL(c.checkin_status, 0) AS checkinStatus, c.checkin_time AS checkinTime, AS runtimeStatus FROM event_signup s INNER JOIN event_info e ON e.id = s.event_id LEFT JOIN event_checkin c ON c.signup_id = s.id WHERE s.user_id = #{userId}
AND s.status = #{query.status}
AND e.title LIKE CONCAT('%', #{query.keyword}, '%')
ORDER BY s.signup_time DESC, s.id DESC

SELECT s.id AS signupId, s.event_id AS eventId, e.title AS eventTitle, s.user_id AS userId, u.username, u.real_name AS realName, u.phone, s.status, s.remark, s.signup_time AS signupTime, s.audit_time AS auditTime, s.cancel_time AS cancelTime, s.audit_by AS auditBy, au.real_name AS auditByName, IFNULL(c.checkin_status, 0) AS checkinStatus, c.checkin_time AS checkinTime FROM event_signup s INNER JOIN event_info e ON e.id = s.event_id INNER JOIN sys_user u ON u.id = s.user_id LEFT JOIN sys_user au ON au.id = s.audit_by LEFT JOIN event_checkin c ON c.signup_id = s.id
AND s.event_id = #{query.eventId}
AND s.status = #{query.status}
AND ( e.title LIKE CONCAT('%', #{query.keyword}, '%') OR u.username LIKE CONCAT('%', #{query.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY s.signup_time DESC, s.id DESC
